query:
{
  dbInstances(
    where: {
      cloudProvider: { eq: "alibaba" }
      engine: { eq: "sqlserver" }
      NOT: {
        OR: [
          { engineVersion_MATCHES: "^2014(\\.|$)" }
          { engineVersion_MATCHES: "^2016(\\.|$)" }
          { engineVersion_MATCHES: "^2017(\\.|$)" }
          { engineVersion_MATCHES: "^2019(\\.|$)" }
        ]
      }
    }
  ) {
    ...AssetFragment
    engine
    engineVersion
  }
}
